 1→// Chat now routes through /api/chat (server-side) which pulls raw DB context
 2→// before calling the gateway. No static biography — OmegA synthesizes from data.
 3→
 4→export interface ChatRequest {
 5→  user: string;
 6→  history?: { role: "user" | "omega"; text: string; timestamp?: string }[];
 7→  sessionId?: string;
 8→}
 9→
10→export interface ChatResponse {
11→  reply?: string;
12→  response?: string;
13→  provider?: string;
14→  sessionId?: string;
15→}
16→
17→export async function chat(req: ChatRequest): Promise<ChatResponse> {
18→  const res = await fetch('/api/chat', {
19→    method: 'POST',
20→    headers: { 'Content-Type': 'application/json' },
21→    body: JSON.stringify(req),
22→  });
23→
24→  if (!res.ok) {
25→    const body = await res.json().catch(() => ({ error: res.statusText }));
26→    throw new Error((body as { error?: string }).error ?? `${res.status}`);
27→  }
28→
29→  return res.json() as Promise<ChatResponse>;
30→}
31→
32→export async function chatStream(
33→  req: ChatRequest, 
34→  onChunk: (text: string) => void,
35→  onStatus?: (text: string) => void
36→): Promise<{ sessionId?: string; provider?: string }> {
37→  const res = await fetch('/api/chat', {
38→    method: 'POST',
39→    headers: { 'Content-Type': 'application/json' },
40→    body: JSON.stringify(req),
41→  });
42→
43→  if (!res.ok) {
44→    const body = await res.json().catch(() => ({ error: res.statusText }));
45→    throw new Error((body as { error?: string }).error ?? `${res.status}`);
46→  }
47→
48→  const sessionId = res.headers.get('X-Session-Id') || undefined;
49→  const provider = res.headers.get('X-Provider') || undefined;
50→
51→  if (!res.body) throw new Error("No response body");
52→
53→  const reader = res.body.getReader();
54→  const decoder = new TextDecoder();
55→  let buffer = "";
56→
57→  while (true) {
58→    const { value, done } = await reader.read();
59→    if (done) break;
60→    const chunkText = decoder.decode(value, { stream: true });
61→    buffer += chunkText;
62→
63→    // Split by SSE double newline if it looks like status events are active
64→    while (buffer.includes('\n\n')) {
65→      const idx = buffer.indexOf('\n\n');
66→      const line = buffer.slice(0, idx).trim();
67→      if (line.startsWith('data: {"type":"status"')) {
68→        try {
69→          const json = JSON.parse(line.slice(5));
70→          if (onStatus) onStatus(json.text);
71→          buffer = buffer.slice(idx + 2);
72→          continue;
73→        } catch {
74→          // fallback if parse fails
75→        }
76→      }
77→      break; // stop if front of buffer isn't a status event
78→    }
79→
80→    if (buffer && !buffer.startsWith('data: {"type":"status"')) {
81→      onChunk(buffer);
82→      buffer = "";
83→    }
84→  }
85→  
86→  // Flush remaining buffer
87→  const final = decoder.decode();
88→  buffer += final;
89→  if (buffer) onChunk(buffer);
90→
91→  return { sessionId, provider };
92→}
