 1→'use client';
 2→
 3→import { useState, useRef, useEffect, useCallback } from 'react';
 4→import s from './InputArea.module.css';
 5→
 6→interface InputAreaProps {
 7→  onSend: (text: string) => void;
 8→  disabled: boolean;
 9→  autoFocus: boolean;
10→}
11→
12→export default function InputArea({ onSend, disabled, autoFocus }: InputAreaProps) {
13→  const [value, setValue] = useState('');
14→  const ref = useRef<HTMLTextAreaElement>(null);
15→
16→  const resize = useCallback(() => {
17→    const el = ref.current;
18→    if (!el) return;
19→    el.style.height = 'auto';
